var topics = ($.input.topics || '').split(',').map(function(t) { return t.trim(); }).filter(function(t) { return t.length > 0; });
var query = 'Latest news about ' + topics.join(' and ');
return { query: query, maxResults: $.input.maxArticles || 10 };

var results = $.steps.searchNews.response.results || [];
var articleList = '';
results.forEach(function(r, i) {
  articleList += '=== ARTICLE ' + (i + 1) + ' ===\n';
  articleList += 'Title: ' + (r.title || 'Untitled') + '\n';
  articleList += 'URL: ' + (r.url || '') + '\n';
  articleList += 'Date: ' + (r.publishedDate || 'unknown') + '\n';
  articleList += 'Content:\n' + (r.text || '').slice(0, 1500) + '\n\n';
});
return { articleList: articleList, articleCount: results.length };

var data = $.steps.extractArticles.output;
var today = new Date().toISOString().split('T')[0];
var prompt = 'You are a news editor. Create a concise daily news digest from the following articles.\n\n';
prompt += 'DATE: ' + today + '\n';
prompt += 'TOPICS: ' + $.input.topics + '\n';
prompt += 'ARTICLES (' + data.articleCount + '):\n' + data.articleList + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write a brief 2-3 sentence overview of the day\'s news\n';
prompt += '- Summarize each article in 1-2 sentences\n';
prompt += '- Group articles by topic if applicable\n';
prompt += '- Highlight the most important story\n';
prompt += '- Use clean HTML formatting suitable for email\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "digestTitle": "Daily Digest - date",\n';
prompt += '  "overview": "Overall summary of today\'s news",\n';
prompt += '  "topStory": { "title": "...", "summary": "...", "url": "..." },\n';
prompt += '  "articles": [\n';
prompt += '    { "title": "...", "summary": "...", "url": "...", "topic": "...", "importance": "High|Medium|Low" }\n';
prompt += '  ],\n';
prompt += '  "htmlBody": "Full HTML email body with all articles formatted nicely"\n';
prompt += '}';
return { prompt: prompt, today: today };

let raw = $.steps.aiDigest.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { digestTitle: 'Daily News Digest', overview: '', topStory: {}, articles: [], htmlBody: '<p>' + raw.replace(/\n/g, '<br>') + '</p>' }; }

var ai = $.steps.parseAI.output;
var html = ai.htmlBody || '';
if (!html || html.length < 50) {
  html = '<h2>' + (ai.digestTitle || 'Daily Digest') + '</h2>';
  html += '<p>' + (ai.overview || '') + '</p>';
  if (ai.topStory && ai.topStory.title) {
    html += '<h3>Top Story</h3>';
    html += '<p><strong>' + ai.topStory.title + '</strong><br>' + (ai.topStory.summary || '') + '<br><a href="' + (ai.topStory.url || '#') + '">Read more</a></p>';
  }
  var articles = ai.articles || [];
  if (articles.length > 0) {
    html += '<h3>All Stories</h3><ul>';
    articles.forEach(function(a) {
      html += '<li><strong>' + a.title + '</strong> [' + (a.importance || '') + ']<br>' + (a.summary || '') + '<br><a href="' + (a.url || '#') + '">Read more</a></li>';
    });
    html += '</ul>';
  }
  html += '<hr><p><small>Generated with Exa + Claude AI via One CLI</small></p>';
}
var subject = ai.digestTitle || ('Daily News Digest - ' + $.steps.buildPrompt.output.today);
return { subject: subject, htmlBody: html.slice(0, 1900) };
